const env = require('frontend-env');

const moduleName = require('../../../package.json').name;

/**
 * Use [Stack Trace API][https://v8.dev/docs/stack-trace-api#customizing-stack-traces] to get stack trace
 *
 * @returns {Array<NodeJS.CallSite>}
 */
const getStackTrace = () => {
  const dummyObject = {};
  // eslint-disable-next-line @typescript-eslint/unbound-method
  const v8Handler = Error.prepareStackTrace;

  Error.prepareStackTrace = function prepareStackTrace(_, v8StackTrace) {
    return v8StackTrace;
  };
  Error.captureStackTrace(dummyObject);

  const v8StackTrace = dummyObject.stack;

  Error.prepareStackTrace = v8Handler;

  return v8StackTrace;
};

const MODULE_PATH = `node_modules/${moduleName}`;

const getPoolName = () => {
  /**
   * It'll give us an object containing information from where the RestClient was called
   */
  const trace = getStackTrace();

  const callerTrace = trace.find((caller) => {
    const fileName = caller?.getFileName();

    if (!fileName) {
      return false; // Sometimes getFileName() might return undefined
    }

    // We'll get the first call that wasn't from this exact same module, we're slicing the stacktrace
    return !fileName.includes(MODULE_PATH);
  });

  // Fallback to getFileName in case we get undefined or falsy value on getEvalOrigin
  const relativeEvalOriginPath = (
    callerTrace?.getEvalOrigin() ||
    callerTrace?.getFileName() ||
    ''
  ).replace(env.PWD, '');

  return relativeEvalOriginPath;
};

module.exports = { getPoolName };
